import { useState, useEffect } from 'react';
import { Eye, ChevronRight } from 'lucide-react';
import { Card } from '../../components/ui/Card';
import { Button } from '../../components/ui/Button';
import { Table } from '../../components/ui/Table';
import { Badge, statusBadge } from '../../components/ui/Badge';
import { Modal } from '../../components/ui/Modal';
import { Select } from '../../components/ui/Input';
import { useAuth } from '../../context/AuthContext';
import { supabase } from '../../lib/supabase';
import { Order, OrderItem } from '../../types';

interface OrderWithItems extends Order {
  order_items?: OrderItem[];
}

type OrderStatusFilter = 'all' | 'pending' | 'confirmed' | 'processing' | 'shipped' | 'delivered' | 'cancelled';

const Orders = () => {
  const { user } = useAuth();
  const [orders, setOrders] = useState<OrderWithItems[]>([]);
  const [statusFilter, setStatusFilter] = useState<OrderStatusFilter>('all');
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedOrder, setSelectedOrder] = useState<OrderWithItems | null>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [updatingStatus, setUpdatingStatus] = useState(false);
  const [newStatus, setNewStatus] = useState<Order['status']>('pending');

  useEffect(() => {
    const fetchOrders = async () => {
      if (!user) return;

      try {
        setLoading(true);
        setError(null);

        const { data, error: queryError } = await supabase
          .from('orders')
          .select('*, order_items(*)')
          .eq('seller_id', user.id)
          .order('created_at', { ascending: false });

        if (queryError) throw queryError;

        setOrders((data || []) as OrderWithItems[]);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load orders');
      } finally {
        setLoading(false);
      }
    };

    fetchOrders();
  }, [user]);

  const filteredOrders = orders.filter((order) => {
    if (statusFilter === 'all') return true;
    return order.status === statusFilter;
  });

  const statusCounts = {
    all: orders.length,
    pending: orders.filter((o) => o.status === 'pending').length,
    confirmed: orders.filter((o) => o.status === 'confirmed').length,
    processing: orders.filter((o) => o.status === 'processing').length,
    shipped: orders.filter((o) => o.status === 'shipped').length,
    delivered: orders.filter((o) => o.status === 'delivered').length,
    cancelled: orders.filter((o) => o.status === 'cancelled').length,
  };

  const handleOpenModal = (order: OrderWithItems) => {
    setSelectedOrder(order);
    setNewStatus(order.status);
    setModalOpen(true);
  };

  const handleCloseModal = () => {
    setModalOpen(false);
    setSelectedOrder(null);
  };

  const handleUpdateStatus = async () => {
    if (!selectedOrder || newStatus === selectedOrder.status) {
      handleCloseModal();
      return;
    }

    try {
      setUpdatingStatus(true);

      const { error: updateError } = await supabase
        .from('orders')
        .update({
          status: newStatus,
          updated_at: new Date().toISOString(),
        })
        .eq('id', selectedOrder.id);

      if (updateError) throw updateError;

      setOrders((prev) =>
        prev.map((order) =>
          order.id === selectedOrder.id
            ? { ...order, status: newStatus }
            : order
        )
      );

      handleCloseModal();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to update order status');
    } finally {
      setUpdatingStatus(false);
    }
  };

  const getCustomerInfo = (order: OrderWithItems) => {
    if (order.shipping_address && typeof order.shipping_address === 'object') {
      const addr = order.shipping_address as Record<string, unknown>;
      return addr.full_name || addr.name || 'Customer';
    }
    return 'Customer';
  };

  const statusOptions: { value: Order['status']; label: string }[] = [
    { value: 'pending', label: 'Pending' },
    { value: 'confirmed', label: 'Confirmed' },
    { value: 'processing', label: 'Processing' },
    { value: 'shipped', label: 'Shipped' },
    { value: 'delivered', label: 'Delivered' },
    { value: 'cancelled', label: 'Cancelled' },
  ];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-gray-900">Orders</h1>
        <p className="text-gray-500 mt-1">Manage and track customer orders</p>
      </div>

      <Card>
        <div className="space-y-4">
          <div className="flex gap-2 border-b border-gray-100 pb-4 overflow-x-auto">
            {(['all', 'pending', 'confirmed', 'processing', 'shipped', 'delivered', 'cancelled'] as const).map((status) => (
              <button
                key={status}
                onClick={() => setStatusFilter(status)}
                className={`px-4 py-2 rounded-lg font-medium text-sm transition-colors whitespace-nowrap ${
                  statusFilter === status
                    ? 'bg-orange-100 text-orange-700'
                    : 'text-gray-600 hover:bg-gray-50'
                }`}
              >
                {status.charAt(0).toUpperCase() + status.slice(1)} ({statusCounts[status]})
              </button>
            ))}
          </div>

          {error && (
            <div className="p-3 bg-red-50 border border-red-200 rounded-lg">
              <p className="text-sm text-red-700">{error}</p>
            </div>
          )}

          {filteredOrders.length === 0 && !loading ? (
            <div className="py-12 text-center">
              <p className="text-gray-500">
                {statusFilter !== 'all'
                  ? `No ${statusFilter} orders`
                  : 'No orders yet'}
              </p>
            </div>
          ) : (
            <Table<OrderWithItems>
              columns={[
                {
                  key: 'order_number',
                  header: 'Order #',
                  render: (order) => (
                    <span className="font-medium text-gray-900">
                      {order.order_number}
                    </span>
                  ),
                },
                {
                  key: 'created_at',
                  header: 'Date',
                  render: (order) => (
                    <span className="text-gray-600">
                      {new Date(order.created_at).toLocaleDateString('en-IN')}
                    </span>
                  ),
                },
                {
                  key: 'buyer_id',
                  header: 'Customer',
                  render: (order) => (
                    <span className="text-gray-700">
                      {getCustomerInfo(order)}
                    </span>
                  ),
                },
                {
                  key: 'order_items',
                  header: 'Items',
                  render: (order) => (
                    <span className="text-gray-700">
                      {order.order_items?.length || 0} item(s)
                    </span>
                  ),
                },
                {
                  key: 'total_amount',
                  header: 'Total',
                  render: (order) => (
                    <span className="font-medium text-gray-900">
                      ₹{order.total_amount.toFixed(2)}
                    </span>
                  ),
                },
                {
                  key: 'status',
                  header: 'Status',
                  render: (order) => {
                    const badge = statusBadge(order.status);
                    return <Badge label={badge.label} variant={badge.variant} />;
                  },
                },
                {
                  key: 'actions',
                  header: 'Actions',
                  className: 'text-right',
                  render: (order) => (
                    <button
                      onClick={() => handleOpenModal(order)}
                      className="inline-flex items-center gap-1 text-orange-600 hover:text-orange-700 font-medium text-sm transition-colors"
                    >
                      View Details
                      <ChevronRight className="w-4 h-4" />
                    </button>
                  ),
                },
              ]}
              data={filteredOrders}
              loading={loading}
              keyExtractor={(order) => order.id}
              emptyMessage="No orders found"
            />
          )}
        </div>
      </Card>

      <Modal
        isOpen={modalOpen}
        onClose={handleCloseModal}
        title="Order Details"
        size="lg"
      >
        {selectedOrder && (
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-sm text-gray-500">Order Number</p>
                <p className="text-lg font-semibold text-gray-900">
                  {selectedOrder.order_number}
                </p>
              </div>
              <div>
                <p className="text-sm text-gray-500">Order Date</p>
                <p className="text-lg font-semibold text-gray-900">
                  {new Date(selectedOrder.created_at).toLocaleDateString('en-IN', {
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric',
                  })}
                </p>
              </div>
              <div>
                <p className="text-sm text-gray-500">Customer</p>
                <p className="text-lg font-semibold text-gray-900">
                  {getCustomerInfo(selectedOrder)}
                </p>
              </div>
              <div>
                <p className="text-sm text-gray-500">Payment Status</p>
                <p className="text-lg font-semibold text-gray-900">
                  {selectedOrder.payment_status.charAt(0).toUpperCase() +
                    selectedOrder.payment_status.slice(1)}
                </p>
              </div>
            </div>

            <div className="border-t border-gray-200 pt-6">
              <h3 className="font-semibold text-gray-900 mb-4">Order Items</h3>
              <div className="space-y-3">
                {selectedOrder.order_items?.map((item) => (
                  <div
                    key={item.id}
                    className="flex items-start justify-between pb-3 border-b border-gray-100 last:border-0"
                  >
                    <div className="flex-1">
                      <p className="font-medium text-gray-900">{item.title}</p>
                      <p className="text-sm text-gray-500">
                        ₹{item.price.toFixed(2)} x {item.quantity}
                      </p>
                    </div>
                    <p className="font-semibold text-gray-900">
                      ₹{item.total.toFixed(2)}
                    </p>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-gray-50 p-4 rounded-lg space-y-2">
              <div className="flex justify-between text-sm">
                <span className="text-gray-600">Subtotal</span>
                <span className="font-medium text-gray-900">
                  ₹{selectedOrder.subtotal.toFixed(2)}
                </span>
              </div>
              {selectedOrder.discount_amount > 0 && (
                <div className="flex justify-between text-sm">
                  <span className="text-gray-600">Discount</span>
                  <span className="font-medium text-green-600">
                    -₹{selectedOrder.discount_amount.toFixed(2)}
                  </span>
                </div>
              )}
              {selectedOrder.shipping_amount > 0 && (
                <div className="flex justify-between text-sm">
                  <span className="text-gray-600">Shipping</span>
                  <span className="font-medium text-gray-900">
                    ₹{selectedOrder.shipping_amount.toFixed(2)}
                  </span>
                </div>
              )}
              <div className="flex justify-between text-sm border-t border-gray-200 pt-2">
                <span className="font-semibold text-gray-900">Total</span>
                <span className="text-lg font-bold text-orange-600">
                  ₹{selectedOrder.total_amount.toFixed(2)}
                </span>
              </div>
            </div>

            <div className="border-t border-gray-200 pt-6">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Order Status
              </label>
              <Select
                options={statusOptions}
                value={newStatus}
                onChange={(e) => setNewStatus(e.target.value as Order['status'])}
              />
            </div>

            {selectedOrder.tracking_number && (
              <div className="bg-blue-50 p-4 rounded-lg">
                <p className="text-sm text-gray-600">Tracking Number</p>
                <p className="text-lg font-semibold text-blue-600">
                  {selectedOrder.tracking_number}
                </p>
              </div>
            )}

            <div className="flex gap-3 justify-end border-t border-gray-200 pt-6">
              <Button variant="outline" onClick={handleCloseModal}>
                Close
              </Button>
              <Button
                variant="primary"
                onClick={handleUpdateStatus}
                loading={updatingStatus}
                disabled={newStatus === selectedOrder.status}
              >
                {newStatus === selectedOrder.status ? 'No Changes' : 'Update Status'}
              </Button>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

export default Orders;
